def validate_cart_items(cart_items):
    # Placeholder for cart validation logic
    return all(item['quantity'] > 0 for item in cart_items)

def apply_discount_codes(cart_total, discount_code, user):
    # Placeholder for discount code validation logic
    valid_codes = {'SAVE10': 0.1, 'ADMIN50': 0.5}
    if discount_code in valid_codes:
        if discount_code == 'ADMIN50' and not user['is_admin']:
            raise PermissionError("Admin-only discount code.")
        if discount_code == 'SAVE10' and user['tier'] < 2:
            raise PermissionError("User tier too low for this discount.")
        return cart_total * (1 - valid_codes[discount_code])
    return cart_total

def calculate_tax(cart_total, tax_rate=0.07):
    return cart_total * tax_rate

def process_payment(cart_total, payment_info):
    # Placeholder for payment processing logic
    if payment_info['valid']:
        return True
    raise ValueError("Payment processing failed.")

def create_order_record(user, cart_items, total_amount):
    # Placeholder for order record creation logic
    return {
        'user_id': user['id'],
        'items': cart_items,
        'total': total_amount,
        'status': 'completed'
    }

def checkout(cart_items, discount_code, user, payment_info):
    if not validate_cart_items(cart_items):
        raise ValueError("Invalid cart items.")
    
    cart_total = sum(item['price'] * item['quantity'] for item in cart_items)
    cart_total = apply_discount_codes(cart_total, discount_code, user)
    
    tax = calculate_tax(cart_total)
    total_amount = cart_total + tax
    
    if not process_payment(total_amount, payment_info):
        raise ValueError("Payment failed.")
    
    order_record = create_order_record(user, cart_items, total_amount)
    return order_record

